sys_script.script:
(function executeRule(current, previous) {

    if (current.employee.nil()) return;

    // Get the employee record
    var emp = new GlideRecord('x_1954179_employ_0_employee');
    if (emp.get(current.employee)) {

        var daysToDeduct = parseFloat(current.total_days.toString()) || 0;
        var currentBalance = parseFloat(emp.leave_balance.toString()) || 0;

        // Make sure balance doesn't go negative
        if (daysToDeduct > currentBalance) {
            gs.addErrorMessage('Insufficient leave balance. Available: ' 
                + currentBalance + ' days, Requested: ' + daysToDeduct + ' days.');
            current.setAbortAction(true);
            return;
        }

        emp.leave_balance = currentBalance - daysToDeduct;
        emp.update();

        gs.addInfoMessage('Leave balance updated. New balance: ' 
            + (currentBalance - daysToDeduct) + ' days.');
    }

})(current, previous);
